import{_ as e,o as a,c as n,a0 as s}from"./chunks/framework.B3sz4m_N.js";const i=""+new URL("../report/agentic-techniques-06-pattern-matching.png",import.meta.url).href,g=JSON.parse(`{"title":"Pattern Matching","description":"How the Dark Factory workflow maps to the Agentic Engineering Book's pattern catalogue — alignment, gaps, and composition opportunities.","frontmatter":{"title":"Pattern Matching","description":"How the Dark Factory workflow maps to the Agentic Engineering Book's pattern catalogue — alignment, gaps, and composition opportunities."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/06-pattern-matching.md","filePath":"reports/agentic-engineering-techniques/06-pattern-matching.md"}`),o={name:"reports/agentic-engineering-techniques/06-pattern-matching.md"};function r(l,t,p,c,d,h){return a(),n("div",null,[...t[0]||(t[0]=[s('<figure class="report-section-image-wrapper" aria-labelledby="fig-patterns-caption"><img src="'+i+`" alt="A weaver&#39;s loom with some threads completed and others waiting to be woven in" loading="lazy" class="report-section-image"><figcaption id="fig-patterns-caption">Weaving established patterns into the existing workflow fabric</figcaption></figure><h2 id="_6-pattern-matching" tabindex="-1">6. Pattern Matching <a class="header-anchor" href="#_6-pattern-matching" aria-label="Permalink to &quot;6. Pattern Matching&quot;">​</a></h2><p>The book catalogues ten distinct agentic patterns, each with specific trade-offs and use cases. This section maps the existing workflow to the pattern catalogue and identifies composition opportunities.</p><h3 id="current-workflow-vs-book-patterns" tabindex="-1">Current workflow vs book patterns <a class="header-anchor" href="#current-workflow-vs-book-patterns" aria-label="Permalink to &quot;Current workflow vs book patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Book Pattern</th><th>Workflow Equivalent</th><th>Alignment</th><th>Key Gap</th></tr></thead><tbody><tr><td><strong>Council Pattern</strong></td><td>Sequential skill chain</td><td><strong>Strong</strong></td><td>Not parallel</td></tr><tr><td><strong>Orchestrator Pattern</strong></td><td>One-shot runner / manual workflow</td><td>Moderate</td><td>No context isolation, no parallelism</td></tr><tr><td><strong>Plan-Build-Review</strong></td><td>No equivalent</td><td>None</td><td>No Plan or Review phase</td></tr><tr><td><strong>Human-in-the-Loop</strong></td><td>Implicit (user reviews output)</td><td>Weak</td><td>No formal approval gates</td></tr><tr><td><strong>Expert Swarm</strong></td><td>No equivalent</td><td>None</td><td>Could apply to multiple initiatives</td></tr><tr><td><strong>Self-Improving Experts</strong></td><td>No equivalent</td><td>None</td><td>No feedback or learning loop</td></tr><tr><td><strong>Progressive Disclosure</strong></td><td>No equivalent</td><td>None</td><td>No on-demand context loading</td></tr><tr><td><strong>Autonomous Loops</strong></td><td>No equivalent</td><td>N/A</td><td>Not applicable to research workflow</td></tr><tr><td><strong>ReAct</strong></td><td>No equivalent</td><td>N/A</td><td>Not applicable to research workflow</td></tr><tr><td><strong>Production Multi-Agent Systems</strong></td><td>No equivalent</td><td>N/A</td><td>Not applicable at current scale</td></tr></tbody></table><h3 id="the-council-pattern-—-strongest-match" tabindex="-1">The Council Pattern — strongest match <a class="header-anchor" href="#the-council-pattern-—-strongest-match" aria-label="Permalink to &quot;The Council Pattern — strongest match&quot;">​</a></h3><p>The workflow&#39;s architecture closely matches the book&#39;s Council Pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Lead (orchestrator, aggregates findings)</span></span>
<span class="line"><span>├── Security Analyst: Read, Grep only</span></span>
<span class="line"><span>├── Performance Auditor: Read, Grep only</span></span>
<span class="line"><span>├── Code Quality Reviewer: Read, Grep only</span></span>
<span class="line"><span>└── ... (each analyst provides independent perspective)</span></span></code></pre></div><p>In the Dark Factory context:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reconciliation Agent (aggregates findings)</span></span>
<span class="line"><span>├── Architect: system design analysis</span></span>
<span class="line"><span>├── Dev-Lead: implementation feasibility</span></span>
<span class="line"><span>├── DevOps: infrastructure and reliability</span></span>
<span class="line"><span>├── Governance: security and compliance</span></span>
<span class="line"><span>├── Critic: stress testing</span></span>
<span class="line"><span>├── Cost-Governor: budget enforcement</span></span>
<span class="line"><span>└── Strategist: business prioritisation</span></span></code></pre></div><p>The Council Pattern&#39;s key characteristics — independent analysis, parallel execution, read-only experts, and lead synthesis — map directly to the workflow. The critical missing element is <strong>parallel execution</strong>: the book explicitly states that council members should analyse simultaneously, with synthesis happening after all perspectives are gathered.</p><h3 id="missing-pattern-plan-build-review" tabindex="-1">Missing pattern: Plan-Build-Review <a class="header-anchor" href="#missing-pattern-plan-build-review" aria-label="Permalink to &quot;Missing pattern: Plan-Build-Review&quot;">​</a></h3><p>The book recommends Plan-Build-Review as the default pattern when uncertain. It separates thinking from doing and catches errors before implementation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan Phase → Build Phase → Review Phase</span></span></code></pre></div><p>The current workflow is all &quot;Build&quot; — agents produce analysis without an explicit planning or review step. Adding these phases would look like:</p><p><strong>Plan Phase (before agents run):</strong> The orchestrator reviews the initiative intake and creates a research plan:</p><ul><li>Which agents are needed for this initiative?</li><li>What context should each agent receive?</li><li>Are there any ambiguities to resolve before agents run?</li><li>What does success look like for this analysis?</li></ul><p><strong>Build Phase (the existing workflow):</strong> Agents run their analysis, now guided by the research plan.</p><p><strong>Review Phase (after reconciliation):</strong> Systematic evaluation of the reconciled output:</p><ul><li>Does the plan address the original initiative?</li><li>Are all sections of the Required Output Structure present?</li><li>Are recommendations internally consistent?</li><li>Run the evaluation rubric against the output</li></ul><h3 id="missing-pattern-human-in-the-loop" tabindex="-1">Missing pattern: Human-in-the-Loop <a class="header-anchor" href="#missing-pattern-human-in-the-loop" aria-label="Permalink to &quot;Missing pattern: Human-in-the-Loop&quot;">​</a></h3><p>The workflow has implicit human review (the user reads and evaluates the reconciliation output), but no formal approval gates. The book identifies specific points where human judgment is most valuable:</p><p><strong>High-value approval gates for the research workflow:</strong></p><ol><li><strong>After Plan Phase</strong> — does the research plan cover the right concerns?</li><li><strong>After Phase 1 agents</strong> — are individual analyses on track before synthesis?</li><li><strong>After reconciliation</strong> — is the final plan coherent and implementable?</li></ol><p>The book warns against gating every step (too much friction) and against gating nothing (too much risk). For a research workflow, gate 1 and 3 provide the best balance.</p><h3 id="composition-opportunity-council-plan-build-review" tabindex="-1">Composition opportunity: Council + Plan-Build-Review <a class="header-anchor" href="#composition-opportunity-council-plan-build-review" aria-label="Permalink to &quot;Composition opportunity: Council + Plan-Build-Review&quot;">​</a></h3><p>The book describes a common composition pattern: each domain expert uses Plan-Build-Review internally while an orchestrator coordinates parallel execution.</p><p>Applied to the Dark Factory workflow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan Phase:</span></span>
<span class="line"><span>  Orchestrator reviews intake, creates research plan</span></span>
<span class="line"><span>  [Human approval gate]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Build Phase:</span></span>
<span class="line"><span>  Phase 1 (parallel): architect + dev-lead + devops + governance</span></span>
<span class="line"><span>  Phase 2 (parallel): critic + cost-governor</span></span>
<span class="line"><span>  Phase 3 (sequential): strategist</span></span>
<span class="line"><span>  Phase 4 (sequential): reconciliation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Review Phase:</span></span>
<span class="line"><span>  Run evaluation rubric against reconciled output</span></span>
<span class="line"><span>  Compare against golden examples (eval cases)</span></span>
<span class="line"><span>  [Human approval gate]</span></span></code></pre></div><p>This composition adds structure without fundamentally changing the workflow. The agents themselves don&#39;t need modification — only the orchestration layer changes.</p><h3 id="pattern-selection-decision-tree" tabindex="-1">Pattern selection decision tree <a class="header-anchor" href="#pattern-selection-decision-tree" aria-label="Permalink to &quot;Pattern selection decision tree&quot;">​</a></h3><p>The book provides a decision tree for choosing patterns. Applied to the research workflow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What kind of task? → Architectural/Creative Decision</span></span>
<span class="line"><span>  └── Does it need multiple expert perspectives? → Yes</span></span>
<span class="line"><span>      └── Orchestrator (parallel domain experts) ✓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Are completion criteria machine-verifiable? → No</span></span>
<span class="line"><span>  └── Plan-Build-Review (human judges completion) ✓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Must a human approve certain steps? → Yes (research output)</span></span>
<span class="line"><span>  └── Human-in-the-Loop (explicit approval gates) ✓</span></span></code></pre></div><p>All three branches converge on the same recommendation: <strong>Orchestrator + Plan-Build-Review + Human-in-the-Loop</strong>. This is the pattern composition the book considers most robust for complex multi-perspective analysis tasks.</p><h3 id="expert-swarm-—-future-opportunity" tabindex="-1">Expert Swarm — future opportunity <a class="header-anchor" href="#expert-swarm-—-future-opportunity" aria-label="Permalink to &quot;Expert Swarm — future opportunity&quot;">​</a></h3><p>The Expert Swarm pattern becomes relevant when running <strong>multiple initiatives in parallel</strong> (the portfolio workflow). Key characteristics:</p><ul><li>Expert lead maintains domain expertise in <code>expertise.yaml</code> (analogous to the skill SKILL.md)</li><li>Workers are spawned for each initiative, inheriting expertise via path-passing</li><li>Workers execute in parallel, each with its own context</li><li>Learning happens after execution (improve agent updates expertise)</li></ul><p>This pattern would apply if the workflow scales to evaluating 5+ initiatives simultaneously. At current scale (1–2 initiatives at a time), the overhead exceeds the benefit.</p><h3 id="anti-patterns-to-avoid" tabindex="-1">Anti-patterns to avoid <a class="header-anchor" href="#anti-patterns-to-avoid" aria-label="Permalink to &quot;Anti-patterns to avoid&quot;">​</a></h3><p>The book identifies patterns that look promising but cause problems:</p><table tabindex="0"><thead><tr><th>Anti-Pattern</th><th>Description</th><th>Relevance</th></tr></thead><tbody><tr><td>Emergency Context Rewriting</td><td>Full context rewrites when hitting token limits</td><td>Avoid — use context isolation instead</td></tr><tr><td>Mixing one-shot and conversational</td><td>One-shot prompts that ask clarifying questions</td><td>The one-shot runner should be self-contained</td></tr><tr><td>Over-constraining process</td><td>Constraining how the agent works, not what it produces</td><td>Skills correctly constrain output, not process</td></tr><tr><td>Evaluation Theatre</td><td>Elaborate eval suite, nobody acts on findings</td><td>Risk if rubric is applied without action on results</td></tr></tbody></table>`,41)])])}const m=e(o,[["render",r]]);export{g as __pageData,m as default};
